/* cam2qr site — animated canvas figures for index.html and how-it-works.html.
   Every <canvas data-viz="…"> runs a small looping "simulation" of its pipeline
   stage. Animations start when scrolled into view, pause off-screen, honor
   prefers-reduced-motion (a single representative frame is drawn instead), and
   re-read the accent color each frame so the theme toggle just works. */

/* Embedded QR matrix (v2, 25×25, generated by this repo's toolchain).
   Shared with the hero animation in index.html. */
const QR_SIZE = 25;
const QR_HEX =
  'febc3fc148506ebd4bb74755dbad6aec127507faaafe0025009ff7cbdcbd8f8788dd349764f6eb6b0fa7484b2b8f3f321feda3d9fb0068c5bfbbaa3056b10ba95f8dd56d0ee8d43f043af7fedcc48';
const QR_BITS = (() => {
  let bits = '';
  for (const ch of QR_HEX) bits += parseInt(ch, 16).toString(2).padStart(4, '0');
  return bits;
})();
const qrModule = (x, y) => QR_BITS[y * QR_SIZE + x] === '1';
const css = (name) => getComputedStyle(document.documentElement).getPropertyValue(name).trim();

const INK = '#14140f';
const PAPER = '#ffffff';
const MUTED = '#8a887c';
const FAINT = '#d8d6cc';

/* ————— timeline helpers ————— */
const clamp01 = (v) => (v < 0 ? 0 : v > 1 ? 1 : v);
/** Progress 0→1 across the [a, b] slice of the timeline. */
const seg = (t, a, b) => clamp01((t - a) / (b - a));
const ease = (p) => (p < 0.5 ? 2 * p * p : 1 - 2 * (1 - p) * (1 - p));
const lerp = (a, b, p) => a + (b - a) * p;

function mono(ctx, px, color, align = 'left') {
  ctx.font = `${px}px ui-monospace, "SF Mono", Menlo, Consolas, monospace`;
  ctx.fillStyle = color;
  ctx.textAlign = align;
  ctx.textBaseline = 'alphabetic';
}

/** The 7-module finder square (ring 3 + core ≤1), top-left at (x, y). */
function finderGlyph(ctx, x, y, m, color = INK) {
  ctx.fillStyle = color;
  ctx.fillRect(x, y, 7 * m, 7 * m);
  ctx.fillStyle = PAPER;
  ctx.fillRect(x + m, y + m, 5 * m, 5 * m);
  ctx.fillStyle = color;
  ctx.fillRect(x + 2 * m, y + 2 * m, 3 * m, 3 * m);
}

function verdict(ctx, x, y, px, good, accent, ok) {
  mono(ctx, px, good ? ok : accent, 'center');
  ctx.fillText(good ? '✓' : '✗', x, y);
}

/* ————— scenes —————
   draw(ctx, w, h, t, c) with t ∈ [0, duration) seconds and c = { accent, ok }.
   staticT is the frame shown under prefers-reduced-motion. */
const SCENES = {
  /* 01 — RGBA → luminance: a sweep line converts color cells to gray. */
  grayscale: {
    duration: 4.6,
    staticT: 4.5,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const cols = 13;
      const rows = 6;
      const ox = 10;
      const oy = 9;
      const gw = w - 20;
      const gh = h - 34;
      const cw = gw / cols;
      const ch = gh / rows;
      const palette = [
        [206, 82, 62], [88, 132, 95], [86, 108, 190], [222, 176, 84],
        [148, 96, 172], [72, 158, 150], [208, 128, 154], [120, 118, 108],
      ];
      const sweep = ease(seg(t, 0.3, 2.8));
      const sweepX = ox + gw * sweep;
      for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
          const [r, g, b] = palette[(x * 3 + y * 5) % palette.length];
          if (ox + (x + 0.5) * cw < sweepX) {
            const luma = (77 * r + 150 * g + 29 * b) >> 8;
            ctx.fillStyle = `rgb(${luma},${luma},${luma})`;
          } else {
            ctx.fillStyle = `rgb(${r},${g},${b})`;
          }
          ctx.fillRect(ox + x * cw, oy + y * ch, cw + 0.5, ch + 0.5);
        }
      }
      if (sweep > 0 && sweep < 1) {
        ctx.strokeStyle = c.accent;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(sweepX, oy - 3);
        ctx.lineTo(sweepX, oy + gh + 3);
        ctx.stroke();
      }
      mono(ctx, fs, sweep >= 1 ? c.accent : MUTED);
      ctx.fillText('luma = (77·R + 150·G + 29·B) >> 8', ox, h - 7);
    },
  },

  /* 02 — adaptive threshold: a window sweeps a gradient-lit texture and
     leaves clean black & white behind it. */
  binarize: {
    duration: 5,
    staticT: 4.9,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const cols = 26;
      const rows = 8;
      const ox = 10;
      const oy = 9;
      const gw = w - 20;
      const gh = h - 34;
      const cw = gw / cols;
      const ch = gh / rows;
      const sweep = ease(seg(t, 0.3, 3.2));
      const sweepX = ox + gw * sweep;
      for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
          const pattern = (x * 7 + y * 13) % 5 < 2; // deterministic "ink"
          if (ox + (x + 0.5) * cw < sweepX) {
            ctx.fillStyle = pattern ? INK : PAPER;
          } else {
            // Illumination ramps across the frame — the global-threshold killer.
            const light = 0.42 + 0.58 * (x / cols);
            const shade = Math.round((pattern ? 74 : 224) * light);
            ctx.fillStyle = `rgb(${shade},${shade},${shade})`;
          }
          ctx.fillRect(ox + x * cw, oy + y * ch, cw + 0.5, ch + 0.5);
        }
      }
      if (sweep > 0 && sweep < 1) {
        // The sliding window whose mean sets the local threshold.
        const win = gh * 0.72;
        ctx.strokeStyle = c.accent;
        ctx.lineWidth = 1.5;
        ctx.setLineDash([3, 3]);
        ctx.strokeRect(sweepX - win / 2, oy + (gh - win) / 2, win, win);
        ctx.setLineDash([]);
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(sweepX, oy - 3);
        ctx.lineTo(sweepX, oy + gh + 3);
        ctx.stroke();
      }
      mono(ctx, fs, sweep >= 1 ? c.accent : MUTED);
      ctx.fillText('dark = below its own window mean', ox, h - 7);
    },
  },

  /* 03 — a scan line sweeps the finder pattern; rows through the center
     read 1:1:3:1:1 and lock the candidate. */
  finder: {
    duration: 4.8,
    staticT: 4.7,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const gh = h - 22;
      const m = gh / 7;
      const ox = 12;
      const oy = 8;
      finderGlyph(ctx, ox, oy, m);

      const sweepEnd = 3;
      const holding = t >= sweepEnd;
      const rowF = holding ? 3.5 : seg(t, 0, sweepEnd) * 7;
      const row = Math.min(6, Math.floor(rowF));
      const lineY = oy + (holding ? 3.5 : rowF) * m;

      ctx.strokeStyle = c.accent;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(ox - 6, lineY);
      ctx.lineTo(ox + 7 * m + 6, lineY);
      ctx.stroke();

      // Run-length encode the row the line is crossing.
      const ring = (x, y) => Math.max(Math.abs(x - 3), Math.abs(y - 3));
      const dark = (x) => ring(x, row) === 3 || ring(x, row) <= 1;
      const runs = [];
      let runStart = 0;
      for (let x = 1; x <= 7; x++) {
        if (x === 7 || dark(x) !== dark(runStart)) {
          runs.push({ len: x - runStart, dark: dark(runStart) });
          runStart = x;
        }
      }
      const match = runs.length === 5 && runs.map((r) => r.len).join(':') === '1:1:3:1:1';

      // Ruler: the row's runs to scale, beside the pattern.
      const rx = ox + 7 * m + 22;
      const unit = Math.min(m, (w - rx - 14) / 7);
      const ry = lineY - 4;
      let x = rx;
      for (const r of runs) {
        const rw = r.len * unit;
        ctx.fillStyle = r.dark ? INK : PAPER;
        ctx.strokeStyle = INK;
        ctx.lineWidth = 1;
        ctx.fillRect(x, ry, rw, 8);
        ctx.strokeRect(x, ry, rw, 8);
        x += rw;
      }
      mono(ctx, fs, match ? c.accent : MUTED);
      ctx.fillText(
        match ? '1:1:3:1:1 ✓' : runs.map((r) => r.len).join(':'),
        rx,
        ry + 8 + fs + 6,
      );

      if (holding || match) {
        // Confirmed center (pulses while locked).
        const pulse = holding ? 2.6 + Math.sin(t * 5) * 0.8 : 2.2;
        ctx.fillStyle = c.accent;
        ctx.beginPath();
        ctx.arc(ox + 3.5 * m, oy + 3.5 * m, pulse, 0, Math.PI * 2);
        ctx.fill();
      }
      if (holding) {
        mono(ctx, fs, c.accent);
        ctx.fillText('center confirmed', rx, ry + 8 + 2 * (fs + 6));
      }
    },
  },

  /* 04 — triple selection: candidate triangles are tried and rejected until
     the right-isosceles corner layout locks. */
  triple: {
    duration: 5.6,
    staticT: 5.5,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const u = h / 130;
      const TL = { x: w * 0.42, y: 26 * u };
      const TR = { x: w * 0.42 + 72 * u, y: 36 * u };
      const BL = { x: w * 0.42 - 10 * u, y: 96 * u };
      const D1 = { x: w * 0.13, y: 62 * u };
      const D2 = { x: w * 0.87, y: 88 * u };
      const points = [TL, TR, BL, D1, D2];
      const trials = [
        { pts: [TL, TR, D1], good: false, from: 0.2 },
        { pts: [D2, TR, BL], good: false, from: 1.5 },
        { pts: [TL, TR, BL], good: true, from: 2.8 },
      ];
      const active = trials.filter((tr) => t >= tr.from).pop();

      const m = 4.6 * u;
      for (const p of points) {
        const decoy = p === D1 || p === D2;
        finderGlyph(ctx, p.x - 3.5 * m, p.y - 3.5 * m, m, decoy ? '#6f6e64' : INK);
      }
      if (active) {
        const appear = seg(t, active.from, active.from + 0.35);
        ctx.strokeStyle = active.good ? c.accent : MUTED;
        ctx.lineWidth = active.good ? 2 : 1.5;
        ctx.globalAlpha = appear;
        ctx.beginPath();
        ctx.moveTo(active.pts[0].x, active.pts[0].y);
        ctx.lineTo(active.pts[1].x, active.pts[1].y);
        ctx.lineTo(active.pts[2].x, active.pts[2].y);
        ctx.closePath();
        ctx.stroke();
        ctx.globalAlpha = 1;
        if (t >= active.from + 0.5) {
          const cx = (active.pts[0].x + active.pts[1].x + active.pts[2].x) / 3;
          const cy = (active.pts[0].y + active.pts[1].y + active.pts[2].y) / 3;
          verdict(ctx, cx, cy + fs * 0.4, fs + 3, active.good, c.accent, c.ok);
        }
        if (active.good && t >= active.from + 0.9) {
          mono(ctx, fs, c.accent, 'center');
          ctx.fillText('TL', TL.x - 3.5 * m - fs, TL.y - 3.5 * m);
          ctx.fillText('TR', TR.x + 3.5 * m + fs, TR.y - 3.5 * m);
          ctx.fillText('BL', BL.x - 3.5 * m - fs, BL.y + 3.5 * m + 2);
        }
      }
      mono(ctx, fs, active?.good && t >= active.from + 0.9 ? c.accent : MUTED);
      ctx.fillText('score: sizes agree · legs equal · corner ≈ 90°', 10, h - 7);
    },
  },

  /* 05 — module size: walk from a finder center toward its neighbor and
     read the transitions at 1.5, 2.5 and 3.5 modules. */
  modulesize: {
    duration: 5.2,
    staticT: 5.1,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const gh = h - 40;
      const m = gh / 7;
      const oy = 8;
      const cy = oy + 3.5 * m;
      const ox1 = 12;
      finderGlyph(ctx, ox1, oy, m);
      const ox2 = w - 12 - 7 * m;
      finderGlyph(ctx, ox2, oy, m);

      const c1 = ox1 + 3.5 * m;
      const c2 = ox2 + 3.5 * m;
      const p = ease(seg(t, 0.3, 2));
      const rayX = lerp(c1, c2, p);
      ctx.strokeStyle = c.accent;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(c1, cy);
      ctx.lineTo(rayX, cy);
      ctx.stroke();

      // Transitions out of the core sit at 1.5 / 2.5 / 3.5 modules.
      // Labels alternate above/below the ray so they don't collide.
      [1.5, 2.5, 3.5].forEach((k, i) => {
        const tx = c1 + k * m;
        if (rayX < tx) return;
        ctx.beginPath();
        ctx.moveTo(tx, cy - 6);
        ctx.lineTo(tx, cy + 6);
        ctx.stroke();
        mono(ctx, fs - 1, c.accent, 'center');
        ctx.fillText(String(k), tx, i % 2 === 0 ? cy - 10 : cy + 10 + fs);
      });
      if (t >= 2.3) {
        mono(ctx, fs, INK);
        ctx.fillText('3 flips → module size in pixels', 12, h - 7 - fs - 4);
      }
      if (t >= 3.1) {
        mono(ctx, fs, c.accent);
        ctx.fillText('center distance ÷ module + 7 ≈ 21 → version 1', 12, h - 7);
      }
    },
  },

  /* 06 — the homography: a perspective-skewed grid straightens into the
     ideal square, anchored by four correspondences. */
  warp: {
    duration: 5.4,
    staticT: 4,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const grid = 5;
      const u = h / 130;
      const skew = [
        [w * 0.3, 16 * u], [w * 0.74, 30 * u], [w * 0.66, 100 * u], [w * 0.24, 84 * u],
      ];
      const side = 82 * u;
      const sx = (w - side) / 2;
      const square = [
        [sx, 14 * u], [sx + side, 14 * u], [sx + side, 14 * u + side], [sx, 14 * u + side],
      ];
      // Morph there and back: skew → square → (hold) → skew.
      const p =
        t < 2.7 ? ease(seg(t, 0.4, 2.2)) : 1 - ease(seg(t, 4.2, 5.3));
      const q = skew.map((s, i) => [lerp(s[0], square[i][0], p), lerp(s[1], square[i][1], p)]);

      const at = (gx, gy) => {
        const top = [lerp(q[0][0], q[1][0], gx), lerp(q[0][1], q[1][1], gx)];
        const bot = [lerp(q[3][0], q[2][0], gx), lerp(q[3][1], q[2][1], gx)];
        return [lerp(top[0], bot[0], gy), lerp(top[1], bot[1], gy)];
      };
      ctx.strokeStyle = INK;
      ctx.lineWidth = 1;
      for (let i = 0; i <= grid; i++) {
        const g = i / grid;
        let a = at(g, 0);
        let b = at(g, 1);
        ctx.beginPath(); ctx.moveTo(a[0], a[1]); ctx.lineTo(b[0], b[1]); ctx.stroke();
        a = at(0, g);
        b = at(1, g);
        ctx.beginPath(); ctx.moveTo(a[0], a[1]); ctx.lineTo(b[0], b[1]); ctx.stroke();
      }
      // The four anchor correspondences.
      ctx.fillStyle = c.accent;
      for (const [x, y] of q) {
        ctx.beginPath();
        ctx.arc(x, y, 3, 0, Math.PI * 2);
        ctx.fill();
      }
      mono(ctx, fs, p > 0.9 ? c.accent : MUTED);
      ctx.fillText('4 correspondences → 3×3 homography', 10, h - 7);
    },
  },

  /* 07 — sampling: one projected read per module center fills the matrix. */
  sample: {
    duration: 4.6,
    staticT: 4.5,
    draw(ctx, w, h, t, c) {
      const n = 10;
      const gh = h - 22;
      const cell = gh / n;
      const ox = 12;
      const oy = 8;
      // "Photo": a window of the embedded QR.
      for (let y = 0; y < n; y++) {
        for (let x = 0; x < n; x++) {
          if (qrModule(x + 8, y + 8)) {
            ctx.fillStyle = INK;
            ctx.fillRect(ox + x * cell, oy + y * cell, cell + 0.5, cell + 0.5);
          }
        }
      }
      const read = Math.floor(ease(seg(t, 0.2, 3)) * n * n);
      ctx.fillStyle = c.accent;
      for (let i = 0; i < read; i++) {
        const x = i % n;
        const y = Math.floor(i / n);
        ctx.beginPath();
        ctx.arc(ox + (x + 0.5) * cell, oy + (y + 0.5) * cell, Math.max(1.4, cell * 0.14), 0, Math.PI * 2);
        ctx.fill();
      }
      // Arrow.
      const ax = ox + n * cell + 16;
      ctx.strokeStyle = c.accent;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(ax, h / 2 - 4);
      ctx.lineTo(ax + 18, h / 2 - 4);
      ctx.lineTo(ax + 13, h / 2 - 9);
      ctx.moveTo(ax + 18, h / 2 - 4);
      ctx.lineTo(ax + 13, h / 2 + 1);
      ctx.stroke();
      // The bit matrix filling in, in sync.
      const mc = Math.min(cell * 0.8, (w - ax - 34) / n);
      const mx = ax + 30;
      const my = (h - n * mc) / 2;
      ctx.strokeStyle = FAINT;
      ctx.lineWidth = 1;
      ctx.strokeRect(mx - 2, my - 2, n * mc + 4, n * mc + 4);
      ctx.fillStyle = INK;
      for (let i = 0; i < read; i++) {
        const x = i % n;
        const y = Math.floor(i / n);
        if (qrModule(x + 8, y + 8)) ctx.fillRect(mx + x * mc, my + y * mc, mc + 0.4, mc + 0.4);
      }
      const fs = Math.max(9, Math.round(h * 0.082));
      mono(ctx, fs, read >= n * n ? c.accent : MUTED);
      ctx.fillText('pixels → bits', ox, h - 6);
    },
  },

  /* 08 — format info: three bits get flipped, BCH(15,5) pulls them back. */
  format: {
    duration: 5.8,
    staticT: 0.6,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const bits = '101010000100101'.split('').map((b) => b === '1');
      const flips = [2, 8, 13];
      const gap = 2;
      const bw = Math.min(16, (w - 30 - gap * 14) / 15);
      const bh = Math.min(20, h * 0.16 + 8);
      const total = 15 * (bw + gap) - gap;
      const ox = (w - total) / 2;
      const oy = h / 2 - bh + 2;

      const damaged = t >= 1.2 && t < 3.4;
      const corrected = t >= 3.4;
      for (let i = 0; i < 15; i++) {
        const x = ox + i * (bw + gap);
        const isData = i < 5;
        const value = damaged && flips.includes(i) ? !bits[i] : bits[i];
        const color = isData ? c.accent : INK;
        if (value) {
          ctx.fillStyle = color;
          ctx.fillRect(x, oy, bw, bh);
        } else {
          ctx.strokeStyle = color;
          ctx.lineWidth = 1.5;
          ctx.strokeRect(x, oy, bw, bh);
        }
        if (damaged && flips.includes(i)) {
          verdict(ctx, x + bw / 2, oy - 5, fs, false, c.accent, c.ok);
        }
        if (corrected && t < 4.6 && flips.includes(i)) {
          ctx.strokeStyle = c.ok;
          ctx.lineWidth = 2;
          ctx.strokeRect(x - 1.5, oy - 1.5, bw + 3, bh + 3);
        }
      }
      mono(ctx, fs, c.accent);
      ctx.fillText('EC + mask', ox, oy + bh + fs + 6);
      mono(ctx, fs, INK, 'right');
      ctx.fillText('BCH(15,5) remainder', ox + total, oy + bh + fs + 6);
      mono(ctx, fs, corrected ? c.ok : MUTED, 'center');
      ctx.fillText(
        corrected ? '3 flips — corrected ✓' : damaged ? '3 bits damaged…' : 'the 15 most protected bits',
        w / 2,
        oy - fs - 4,
      );
    },
  },

  /* 09 — the eight mask formulas, cycling over one grid. */
  masks: {
    duration: 8 * 0.9,
    staticT: 0.4,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const formulas = [
        ['000', '(r+c) % 2 == 0', (r, cc) => (r + cc) % 2 === 0],
        ['001', 'r % 2 == 0', (r) => r % 2 === 0],
        ['010', 'c % 3 == 0', (_, cc) => cc % 3 === 0],
        ['011', '(r+c) % 3 == 0', (r, cc) => (r + cc) % 3 === 0],
        ['100', '(⌊r/2⌋+⌊c/3⌋) % 2 == 0', (r, cc) => (Math.floor(r / 2) + Math.floor(cc / 3)) % 2 === 0],
        ['101', '(r·c)%2 + (r·c)%3 == 0', (r, cc) => ((r * cc) % 2) + ((r * cc) % 3) === 0],
        ['110', '((r·c)%2 + (r·c)%3) % 2 == 0', (r, cc) => (((r * cc) % 2) + ((r * cc) % 3)) % 2 === 0],
        ['111', '((r+c)%2 + (r·c)%3) % 2 == 0', (r, cc) => (((r + cc) % 2) + ((r * cc) % 3)) % 2 === 0],
      ];
      const idx = Math.min(7, Math.floor(t / 0.9));
      const [label, source, fn] = formulas[idx];
      const n = 12;
      const cell = (h - 24) / n;
      const ox = 14;
      const oy = 10;
      ctx.fillStyle = INK;
      for (let r = 0; r < n; r++) {
        for (let cc = 0; cc < n; cc++) {
          if (fn(r, cc)) ctx.fillRect(ox + cc * cell, oy + r * cell, cell - 0.6, cell - 0.6);
        }
      }
      const tx = ox + n * cell + 18;
      mono(ctx, fs + 2, c.accent);
      ctx.fillText(`mask ${label}`, tx, h * 0.38);
      mono(ctx, fs, INK);
      ctx.fillText(source, tx, h * 0.38 + fs + 8);
      mono(ctx, fs, MUTED);
      ctx.fillText(`${idx + 1} / 8 · XOR undoes itself`, tx, h * 0.38 + 2 * (fs + 8));
    },
  },

  /* 10 — the serpentine codeword walk, traced live, grouped into bytes. */
  zigzag: {
    duration: 5.2,
    staticT: 5.1,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const cols = 10;
      const rows = 6;
      const cell = (h - 34) / rows;
      const ox = (w - cols * cell) / 2;
      const oy = 9;
      // Visit order: rightmost two-module band upward, next band downward…
      const path = [];
      for (let band = 0; band < cols / 2; band++) {
        const xRight = cols - band * 2 - 1;
        const up = band % 2 === 0;
        for (let step = 0; step < rows; step++) {
          const row = up ? rows - 1 - step : step;
          path.push([xRight, row], [xRight - 1, row]);
        }
      }
      const visited = Math.floor(seg(t, 0.2, 3.6) * path.length);

      // Completed bytes tint their eight modules, alternating.
      for (let i = 0; i < visited; i++) {
        const byte = Math.floor(i / 8);
        if (byte * 8 + 8 > visited) break;
        const [x, y] = path[i];
        ctx.fillStyle = byte % 2 === 0 ? '#efe4e2' : '#e7eae4';
        ctx.fillRect(ox + x * cell, oy + y * cell, cell, cell);
      }
      ctx.strokeStyle = FAINT;
      ctx.lineWidth = 1;
      for (let i = 0; i <= cols; i++) {
        ctx.beginPath(); ctx.moveTo(ox + i * cell, oy); ctx.lineTo(ox + i * cell, oy + rows * cell); ctx.stroke();
      }
      for (let i = 0; i <= rows; i++) {
        ctx.beginPath(); ctx.moveTo(ox, oy + i * cell); ctx.lineTo(ox + cols * cell, oy + i * cell); ctx.stroke();
      }
      ctx.strokeStyle = c.accent;
      ctx.lineWidth = 2;
      ctx.beginPath();
      for (let i = 0; i < visited; i++) {
        const [x, y] = path[i];
        const px = ox + (x + 0.5) * cell;
        const py = oy + (y + 0.5) * cell;
        if (i === 0) ctx.moveTo(px, py);
        else ctx.lineTo(px, py);
      }
      ctx.stroke();
      if (visited > 0 && visited < path.length) {
        const [hx, hy] = path[visited - 1];
        ctx.fillStyle = c.accent;
        ctx.beginPath();
        ctx.arc(ox + (hx + 0.5) * cell, oy + (hy + 0.5) * cell, 3, 0, Math.PI * 2);
        ctx.fill();
      }
      mono(ctx, fs, MUTED);
      ctx.fillText('bottom-right, upward first', 12, h - 7);
      mono(ctx, fs, visited >= path.length ? c.accent : MUTED, 'right');
      ctx.fillText(`codeword ${Math.floor(visited / 8)}`, w - 12, h - 7);
    },
  },

  /* 11 — Reed–Solomon: damage strikes, the Chien search locates it,
     Forney repairs it. */
  correct: {
    duration: 6,
    staticT: 5.9,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const n = 12;
      const gap = 4;
      const bw = (w - 32 - gap * (n - 1)) / n;
      const bh = Math.min(18, h * 0.15 + 6);
      const ox = 16;
      const oy = h * 0.3;
      const damagedIdx = [3, 8];
      const damaged = t >= 0.9 && t < 3.9;
      const scanning = t >= 1.8 && t < 3.3;
      const fixed = t >= 3.9;

      for (let i = 0; i < n; i++) {
        const x = ox + i * (bw + gap);
        const bad = damaged && damagedIdx.includes(i);
        ctx.fillStyle = bad ? c.accent : INK;
        ctx.fillRect(x, oy, bw, bh);
        if (bad) verdict(ctx, x + bw / 2, oy - 5, fs, false, c.accent, c.ok);
        if (fixed && t < 5 && damagedIdx.includes(i)) {
          ctx.strokeStyle = c.ok;
          ctx.lineWidth = 2;
          ctx.strokeRect(x - 1.5, oy - 1.5, bw + 3, bh + 3);
        }
      }
      if (scanning) {
        // Chien search: try every position, mark the locator's roots.
        const p = seg(t, 1.8, 3.3);
        const cursor = ox + p * (n * (bw + gap) - gap);
        ctx.strokeStyle = c.accent;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(ox, oy + bh + 7);
        ctx.lineTo(cursor, oy + bh + 7);
        ctx.stroke();
        for (const i of damagedIdx) {
          const x = ox + i * (bw + gap) + bw / 2;
          if (cursor >= x) {
            ctx.beginPath();
            ctx.moveTo(x, oy + bh + 4);
            ctx.lineTo(x, oy + bh + 10);
            ctx.stroke();
          }
        }
      }
      const captions = [
        [0, 'received codewords'],
        [0.9, 'two damaged — syndromes ≠ 0'],
        [1.8, 'Berlekamp–Massey + Chien → positions'],
        [3.9, 'Forney → magnitudes · repaired ✓'],
      ];
      let caption = captions[0][1];
      for (const [from, text] of captions) if (t >= from) caption = text;
      mono(ctx, fs, fixed ? c.ok : t >= 0.9 ? c.accent : MUTED);
      ctx.fillText(caption, ox, oy + bh + fs + 16);
      mono(ctx, fs, fixed ? c.accent : MUTED);
      ctx.fillText('ecc.codewordsCorrected: 2', ox, oy + bh + 2 * (fs + 10) + 6);
    },
  },

  /* 12 — segments: the corrected bitstream types itself out into a URL. */
  segments: {
    duration: 6.4,
    staticT: 6.3,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.086));
      const ox = 12;
      // Truncate the bit line to what actually fits this canvas width.
      const fits = Math.floor((w - 2 * ox) / (fs * 0.62));
      const bitLine = '0100 00010010 01101000 01110100 01110100 01110000 0111001…'.slice(0, fits);
      const url = 'https://cam2qr.com';
      const bitChars = Math.floor(seg(t, 0.2, 1.6) * bitLine.length);
      mono(ctx, fs, INK);
      ctx.fillText(bitLine.slice(0, bitChars), ox, h * 0.2);
      if (t >= 1.8) {
        mono(ctx, fs, c.accent);
        ctx.fillText('mode: byte · count: 18', ox, h * 0.2 + fs + 7);
      }
      if (t >= 2.4) {
        ctx.strokeStyle = c.accent;
        ctx.lineWidth = 2;
        const ay = h * 0.2 + fs + 15;
        ctx.beginPath();
        ctx.moveTo(ox + 4, ay);
        ctx.lineTo(ox + 4, ay + 12);
        ctx.lineTo(ox, ay + 8);
        ctx.moveTo(ox + 4, ay + 12);
        ctx.lineTo(ox + 8, ay + 8);
        ctx.stroke();
      }
      if (t >= 2.7) {
        const chars = Math.ceil(seg(t, 2.7, 4) * url.length);
        mono(ctx, fs + 2, INK);
        ctx.fillText(
          `"${url.slice(0, chars)}${chars < url.length ? '▌' : '"'}`,
          ox,
          h * 0.72,
        );
      }
      if (t >= 4.4) {
        mono(ctx, fs, c.ok);
        ctx.fillText('content: { type: "url" } ✓', ox, h * 0.72 + fs + 8);
      }
    },
  },

  /* 13 — the pass plan: cheap attempts first, retries only when needed. */
  passes: {
    duration: 5.6,
    staticT: 5.5,
    draw(ctx, w, h, t, c) {
      const fs = Math.max(9, Math.round(h * 0.082));
      const labels = ['½× pass', 'full res', 'inverted'];
      const starts = [0.4, 1.8, 3.2];
      const good = [false, false, true];
      const chipW = Math.min(104, (w - 40 - 2 * 14) / 3);
      const chipH = Math.max(22, h * 0.2);
      const oy = h * 0.32;
      let x = (w - 3 * chipW - 2 * 14) / 2;
      for (let i = 0; i < 3; i++) {
        const active = t >= starts[i];
        const judged = t >= starts[i] + 0.8;
        const locked = good[i] && judged;
        ctx.strokeStyle = locked ? c.accent : active ? INK : FAINT;
        ctx.lineWidth = locked ? 2 : 1.2;
        ctx.strokeRect(x, oy, chipW, chipH);
        mono(ctx, fs, active ? INK : MUTED, 'center');
        ctx.fillText(labels[i], x + chipW / 2, oy + chipH / 2 + fs * 0.35);
        if (judged) {
          verdict(ctx, x + chipW / 2, oy + chipH + fs + 6, fs + 1, good[i], c.accent, c.ok);
        }
        if (i < 2 && judged) {
          ctx.strokeStyle = MUTED;
          ctx.lineWidth = 1.5;
          ctx.beginPath();
          ctx.moveTo(x + chipW + 3, oy + chipH / 2);
          ctx.lineTo(x + chipW + 11, oy + chipH / 2);
          ctx.stroke();
        }
        x += chipW + 14;
      }
      mono(ctx, fs, t >= starts[2] + 0.8 ? c.ok : MUTED, 'center');
      ctx.fillText(
        t >= starts[2] + 0.8 ? 'decoded on the third pass ✓' : 'a light-on-dark code, slightly blurred',
        w / 2,
        h - 8,
      );
    },
  },
};

/* ————— engine ————— */
(() => {
  const reduceMotion = matchMedia('(prefers-reduced-motion: reduce)');
  const items = [];
  const visible = new Set();

  for (const canvas of document.querySelectorAll('canvas[data-viz]')) {
    const scene = SCENES[canvas.dataset.viz];
    if (!scene) continue;
    const w = canvas.width;
    const h = canvas.height;
    const dpr = Math.min(2.5, window.devicePixelRatio || 1);
    canvas.width = Math.round(w * dpr);
    canvas.height = Math.round(h * dpr);
    canvas.style.maxWidth = `${w}px`;
    canvas.style.aspectRatio = `${w} / ${h}`;
    const ctx = canvas.getContext('2d');
    items.push({ canvas, ctx, scene, w, h, dpr, start: null });
  }
  if (items.length === 0) return;
  const byCanvas = new Map(items.map((item) => [item.canvas, item]));

  function render(item, t) {
    const { ctx, scene, w, h, dpr } = item;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.fillStyle = PAPER;
    ctx.fillRect(0, 0, w, h);
    const colors = {
      accent: css('--accent') || '#d6402f',
      ok: css('--ok') || '#3e7d4e',
    };
    scene.draw(ctx, w, h, t, colors);
    ctx.textAlign = 'left';
  }

  function renderStatic(item) {
    render(item, item.scene.staticT);
  }

  let rafId = null;
  function frame(now) {
    rafId = null;
    for (const item of visible) {
      if (item.start === null) item.start = now;
      render(item, ((now - item.start) / 1000) % item.scene.duration);
    }
    if (visible.size > 0 && !reduceMotion.matches) {
      rafId = requestAnimationFrame(frame);
    }
  }
  function wake() {
    if (rafId === null && visible.size > 0 && !reduceMotion.matches) {
      rafId = requestAnimationFrame(frame);
    }
  }

  const observer = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) {
        const item = byCanvas.get(entry.target);
        if (entry.isIntersecting) visible.add(item);
        else visible.delete(item);
      }
      wake();
    },
    { rootMargin: '60px' },
  );

  for (const item of items) {
    renderStatic(item); // first paint, and the only paint under reduced motion
    observer.observe(item.canvas);
  }

  reduceMotion.addEventListener?.('change', () => {
    if (reduceMotion.matches) {
      for (const item of items) renderStatic(item);
    } else {
      for (const item of items) item.start = null;
      wake();
    }
  });
  window.addEventListener('cam2qr-theme', () => {
    if (reduceMotion.matches) for (const item of items) renderStatic(item);
    else wake();
  });
})();
